#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=1000005;
ll n,q,a[N],add[N],block;
int fun(int x)
{
	return (x-1)/block+1;
}
struct node
{
	ll num,id;
	bool operator<(const node other) const
	{
		return num<other.num;
	}
};
vector<node> v[1005];
void ad(int l,int r,ll w)
{
	int tl=fun(l),tr=fun(r);
	if(tl==tr)
	{
		for(int i=0;i<v[tl].size();i++)
		{
			node tmp=v[tl][i];
			if(tmp.id>=l&&tmp.id<=r)
			{
				v[tl][i].num+=w;
			}
		}
		return ;
	}
	for(int i=tl+1;i<tr;i++)
	{
		add[i]+=w;
	}
	for(int i=0;i<v[tl].size();i++)
	{
		node tmp=v[tl][i];
		if(tmp.id>=l)
		{
			v[tl][i].num+=w;
		}
	}
	for(int i=0;i<v[tr].size();i++)
	{
		node tmp=v[tr][i];
		if(tmp.id<=r)
		{
			v[tr][i].num+=w;
		}
	}
}
int query(int l,int r,ll w)
{
	int tl=fun(l),tr=fun(r),cnt=0;
	if(tl==tr)
	{
		for(int i=0;i<v[tl].size();i++)
		{
			node tmp=v[tl][i];
			if(tmp.id>=l&&tmp.id<=r&&tmp.num>=w-add[tl])
			{
				cnt++;
			}
		}
		return cnt;
	}
	for(int i=0;i<v[tl].size();i++)
	{
		node tmp=v[tl][i];
		if(tmp.id>=l&&tmp.num>=w-add[tl])
		{
			cnt++;
		}
	}
	for(int i=0;i<v[tr].size();i++)
	{
		node tmp=v[tr][i];
		if(tmp.id>=r&&tmp.num>=w-add[tr])
		{
			cnt++;
		}
	}
	for(int i=tl+1;i<tr;i++)
	{
		sort(v[i].begin(),v[i].end());
		auto tmp=lower_bound(v[i].begin(),v[i].end(),node{w-add[i],0});
		int num=v[i].end()-tmp;
		cnt+=num;
	}
	return cnt;
}
int main()
{
	cin>>n>>q;
	block=sqrt(n);
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		v[fun(i)].push_back(node{a[i],i});
	}
	while(q--)
	{
		string s;
		cin>>s;
		int l,r,w;
		cin>>l>>r>>w;
		if(s=="M")
		{
			ad(l,r,w);
		}
		else
		{
			cout<<query(l,r,w)<<"\n";
		}
	}
	return 0;
}
